import{_ as e,o as i,c as a,a as l}from"./chunks/framework.8tiMeCK-.js";const n="/PenguinLab/assets/ch06_fig067.DaWjFOTl.webp",t="/PenguinLab/assets/ch06_fig068.DtmVjMz1.webp",g=JSON.parse('{"title":"6.3  运行并统计 SLUB 测试案例","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch06_3.md","filePath":"notes/linux_kernel_debugging/ch06_3.md","lastUpdated":null}'),p={name:"notes/linux_kernel_debugging/ch06_3.md"};function o(d,s,r,c,h,u){return i(),a("div",null,[...s[0]||(s[0]=[l('<p>现在我们到了验收环节——把那些有问题的测试模块扔进内核里，看看刚才配置的那套安检机制能不能把漏洞抓出来。</p><hr><h1 id="_6-3-运行并统计-slub-测试案例" tabindex="-1">6.3 运行并统计 SLUB 测试案例 <a class="header-anchor" href="#_6-3-运行并统计-slub-测试案例" aria-label="Permalink to &quot;6.3  运行并统计 SLUB 测试案例&quot;">​</a></h1><p>所有的测试代码都堆在同一个模块里：<code>ch5/kmembugs_test/kmembugs_test.c</code>（别忘了还有它的搭档 <code>debugfs_kmembugs.c</code>）。这一节既然是测 SLUB，我们就只挑跟 slab 内存有关的案例跑。</p><p>为了看清差距，我们这次要在两个极端环境下做对比：</p><ol><li><strong>完全关闭调试</strong>：<code>slub_debug=-</code></li><li><strong>全开 SLUB 调试</strong>：<code>slub_debug=FZPU</code></li></ol><p>你可能会问，为什么要跑两种？直接开调试不就完了？</p><p>原因很简单：现实中的发行版内核（比如这里用的 Ubuntu 20.04 LTS）虽然默认开启了 <code>CONFIG_SLUB_DEBUG=y</code>，但并不意味着所有调试特性都在跑。你需要理解「有调试框架」和「开着调试干活」的区别。</p><p>而且还有一个现实原因：如果我们用之前那个编译了 KASAN 和 UBSAN 的调试内核来测，这两个家伙会抢先一步报错——我们就看不到 SLUB 自己的报错了。所以这里我们用纯净的生产内核（<code>5.10.60-prod01</code>）来跑，好让 SLUB 自己唱主角。</p><hr><h3 id="场景一-slub-调试关闭时-slub-debug" tabindex="-1">场景一：SLUB 调试关闭时（<code>slub_debug=-</code>） <a class="header-anchor" href="#场景一-slub-调试关闭时-slub-debug" aria-label="Permalink to &quot;场景一：SLUB 调试关闭时（`slub_debug=-`）&quot;">​</a></h3><p>先把安全网撤掉，看看裸奔是什么情况。这对应 Table 6.2 里的第三列，以及标记为 <code>[V1]</code>、<code>[V2]</code>、<code>[V3]</code> 的行。</p><p>跑起来的结果正如你预料的那样惨淡：</p><ul><li><p><strong>毫无反应</strong>：当 <code>slub_debug=-</code> 时，没有任何内存 bug 被捕获——包括我们的前三项测试（UMR 未初始化内存读、UAR 释放后重用、内存泄漏）全部漏网。</p></li><li><p><strong><code>[V1]</code> 行为不可预测</strong>：系统可能直接 Oops，可能卡死，也可能看起来什么事都没发生——但这才是最可怕的。内核一旦坏了，它就是坏了，只是还没倒下而已。</p></li><li><p><strong><code>[V2]</code> Double-free 的下场</strong>：对于重复释放（double-free）这个缺陷，普通的 vanilla 内核或者生产内核会有反应。它可能会触发段错误，然后给你抛出这样一个报错：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>kernel BUG at mm/slub.c:305!</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这里的指令指针寄存器（x86_64 上的 RIP）正指着 <code>kfree()</code> API。</p><p>这行报错很有意思。我特意去查了主线内核 5.10.60 版本的源码（在 Bootlin 的那个源码浏览器上，非常顺滑）：<a href="https://elixir.bootlin.com/linux/v5.10.60/source/mm/slub.c" target="_blank" rel="noreferrer"><code>mm/slub.c:305</code></a>。</p><p>看图：</p><p><img src="'+n+'" alt="Figure 6.1 – Bootlin 源码截图"></p><p>真是不偏不倚。触发 bug 的正是第 305 行。这说明即使是普通的 vanilla 内核，也保留了最后一丝理智——它能检测出这种「原始」的 double-free，知道这是一种内存破坏。</p></li><li><p><strong><code>[V3]</code> UMR 依然隐形</strong>：至于 slab 内存上的未初始化内存读取（UMR），在生产内核且 <code>slub_debug=-</code> 的状态下，它依然逍遥法外。kmalloc 出来的区域看起来像是被初始化成了 <code>0x0</code>，但这只是假象，你读到了脏数据，而系统没警告你。</p></li></ul><hr><h3 id="场景二-slub-调试开启时-slub-debug-fzpu" tabindex="-1">场景二：SLUB 调试开启时（<code>slub_debug=FZPU</code>） <a class="header-anchor" href="#场景二-slub-调试开启时-slub-debug-fzpu" aria-label="Permalink to &quot;场景二：SLUB 调试开启时（`slub_debug=FZPU`）&quot;">​</a></h3><p>好，现在把安全网拉起来。我们需要重启系统，在 GRUB 里把内核参数改成 <code>slub_debug=FZPU</code>。</p><p>这对应 Table 6.2 里的第四列。</p><p>如果你是通过 VirtualBox 或者直接在真机上操作，编辑 GRUB 启动项大概是这样：</p><p><img src="'+t+`" alt="Figure 6.2 – GRUB 编辑菜单"></p><p>改完重启进系统，第一步永远是确认内核真的收到了你的指令。别懒，这一定要看：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dmesg</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Kernel command line&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[    0.094445] Kernel command line: BOOT_IMAGE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/boot/vmlinuz-5.11.0-40-generic</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> root</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">UUID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">...</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ro</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quiet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> splash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> slub_debug=FZPU</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>看到了末尾的 <code>slub_debug=FZPU</code> 吗？ （当然，跑 <code>cat /proc/cmdline</code> 也能看到同样的结果。）</p><p>行，现在一切就位，把测试模块重新扔进去。</p><p>这一次，局势完全变了。回到 Table 6.2 看看那些标记为 <code>[V4]</code> 的行：</p><p>SLUB 调试机制成功捕获了<strong>越界写</strong>（OOB），无论是向上溢出还是向下溢出，都无所遁形。</p><p>但这里有个微妙的地方值得注意——如果你仔细看测试结果，你会发现 SLUB 的行为和 UBSAN 有点像：它似乎只对「错误的索引越界」敏感，当越界访问是通过指针算术发生的时候，它可能就会漏掉。另外，对于<strong>越界读</strong>（OOB Read），SLUB 在这个配置下似乎也无能为力。</p><p>这很正常。没有哪一种工具是上帝视角，它们各有各的盲区。</p><p>现在，SLUB 已经抓到了坏人，并吐出了一堆错误日志。接下来我们要学的是一项核心技能：如何像侦探一样解读这份 SLUB 调错报告。</p>`,29)])])}const k=e(p,[["render",o]]);export{g as __pageData,k as default};
